//! lwIP BSD socket networking for FreeRTOS.
//!
//! Implements PlatformTcp, PlatformUdp, PlatformSocketHelpers, and
//! PlatformUdpMulticast on FreeRtosPlatform using lwIP's BSD socket API.
//!
//! Types and constants are auto-generated by `freertos-lwip-sys` (bindgen),
//! eliminating manual struct size mismatches (e.g., newlib's 64-bit time_t).

#![allow(unsafe_op_in_unsafe_fn)]

use core::ffi::{c_int, c_void};

use crate::FreeRtosPlatform;
use freertos_lwip_sys::*;

#[cfg(feature = "debug-cortex-m-semihosting")]
macro_rules! dbg_log {
    ($($arg:tt)*) => {
        cortex_m_semihosting::hprintln!("[freertos-net] {}", format_args!($($arg)*));
    };
}
#[cfg(not(feature = "debug-cortex-m-semihosting"))]
macro_rules! dbg_log {
    ($($arg:tt)*) => {{ let _ = format_args!($($arg)*); }};
}

// ============================================================================
// C struct wrappers matching zenoh-pico's FreeRTOS/lwIP platform types
// ============================================================================

/// Socket: `{ int _socket; }` (matches _z_sys_net_socket_t)
#[repr(C)]
struct Socket {
    _socket: c_int,
}

/// Endpoint: `{ struct addrinfo *_iptcp; }` (matches _z_sys_net_endpoint_t)
#[repr(C)]
struct Endpoint {
    _iptcp: *mut addrinfo,
}

/// Phase 71.22 — net buffer sizes (see nros-platform-posix for rationale).
pub const NET_SOCKET_SIZE: usize = core::mem::size_of::<Socket>();
pub const NET_SOCKET_ALIGN: usize = core::mem::align_of::<Socket>();
pub const NET_ENDPOINT_SIZE: usize = core::mem::size_of::<Endpoint>();
pub const NET_ENDPOINT_ALIGN: usize = core::mem::align_of::<Endpoint>();

const Z_TRANSPORT_LEASE: u32 = 10000; // ms

// ============================================================================
// TCP
// ============================================================================

impl FreeRtosPlatform {
    pub fn tcp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let ep = ep as *mut Endpoint;

        let mut hints: addrinfo = unsafe { core::mem::zeroed() };
        hints.ai_family = PF_UNSPEC as c_int;
        hints.ai_socktype = SOCK_STREAM as c_int;
        hints.ai_protocol = IPPROTO_TCP as c_int;

        let ret = unsafe {
            lwip_getaddrinfo(
                address as *const _,
                port as *const _,
                &hints,
                &mut (*ep)._iptcp,
            )
        };
        if ret != 0 {
            return -1;
        }

        // lwIP quirk: getaddrinfo doesn't always set sa_family on the sockaddr.
        // The C code does: ep->_iptcp->ai_addr->sa_family = ep->_iptcp->ai_family;
        unsafe {
            let ai = &*(*ep)._iptcp;
            if !ai.ai_addr.is_null() {
                (*ai.ai_addr).sa_family = ai.ai_family as u8;
            }
        }
        0
    }

    pub fn tcp_free_endpoint(ep: *mut c_void) {
        let ep = ep as *mut Endpoint;
        unsafe {
            if !(*ep)._iptcp.is_null() {
                lwip_freeaddrinfo((*ep)._iptcp);
            }
        }
    }

    pub fn tcp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        if rep._iptcp.is_null() {
            return -1;
        }
        let ai = unsafe { &*rep._iptcp };

        // Fix sa_family if not set
        unsafe {
            if !ai.ai_addr.is_null() && (*ai.ai_addr).sa_family == 0 {
                (*ai.ai_addr).sa_family = ai.ai_family as u8;
            }
        }

        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        // SO_RCVTIMEO
        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        if unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            )
        } < 0
        {
            unsafe { lwip_close(fd) };
            return -1;
        }

        // SO_SNDTIMEO (lwIP blocks on send when congestion window closes)
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_SNDTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        // SO_KEEPALIVE
        let one: c_int = 1;
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_KEEPALIVE as c_int,
                &one as *const _ as *const c_void,
                4,
            );
        }

        // TCP_NODELAY
        unsafe {
            lwip_setsockopt(
                fd,
                IPPROTO_TCP as c_int,
                TCP_NODELAY as c_int,
                &one as *const _ as *const c_void,
                4,
            );
        }

        // SO_LINGER
        let ling = linger {
            l_onoff: 1,
            l_linger: (Z_TRANSPORT_LEASE / 1000) as c_int,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_LINGER as c_int,
                &ling as *const _ as *const c_void,
                core::mem::size_of::<linger>() as u32,
            );
        }

        // Connect — iterate through addrinfo list
        let mut it = rep._iptcp;
        while !it.is_null() {
            let ai = unsafe { &*it };
            let ret = unsafe { lwip_connect(fd, ai.ai_addr, ai.ai_addrlen) };
            if ret == 0 {
                return 0;
            }
            it = ai.ai_next;
        }

        unsafe {
            lwip_close(fd);
            (*sock)._socket = -1;
        }
        -1
    }

    pub fn tcp_listen(sock: *mut c_void, endpoint: *const c_void) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let ai = unsafe { &*rep._iptcp };
        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }

        let one: c_int = 1;
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_REUSEADDR as c_int,
                &one as *const _ as *const c_void,
                4,
            );
        }

        if unsafe { lwip_bind(fd, ai.ai_addr, ai.ai_addrlen) } < 0 {
            unsafe { lwip_close(fd) };
            return -1;
        }

        if unsafe { lwip_listen(fd, 1) } < 0 {
            unsafe { lwip_close(fd) };
            return -1;
        }

        let tv = timeval {
            tv_sec: (Z_TRANSPORT_LEASE / 1000) as _,
            tv_usec: 0 as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        unsafe { (*sock)._socket = fd };
        0
    }

    pub fn tcp_close(sock: *mut c_void) {
        unsafe { lwip_socket_thread_init() };
        let sock = sock as *mut Socket;
        let fd = unsafe { (*sock)._socket };
        if fd >= 0 {
            unsafe {
                lwip_shutdown(fd, SHUT_RDWR as c_int);
                lwip_close(fd);
                (*sock)._socket = -1;
            }
        }
    }

    pub fn tcp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }
        let n = unsafe { lwip_recv(sock._socket, buf as *mut c_void, len, 0) };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn tcp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }

        let mut total: usize = 0;
        while total < len {
            let n =
                unsafe { lwip_recv(sock._socket, buf.add(total) as *mut c_void, len - total, 0) };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }

    pub fn tcp_send(sock: *const c_void, buf: *const u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }

        let mut total: usize = 0;
        while total < len {
            let n = unsafe {
                lwip_send(
                    sock._socket,
                    buf.add(total) as *const c_void,
                    len - total,
                    0,
                )
            };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }
}

// ============================================================================
// UDP
// ============================================================================

impl FreeRtosPlatform {
    pub fn udp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let ep = ep as *mut Endpoint;

        let mut hints: addrinfo = unsafe { core::mem::zeroed() };
        hints.ai_family = PF_UNSPEC as c_int;
        hints.ai_socktype = SOCK_DGRAM as c_int;
        hints.ai_protocol = IPPROTO_UDP as c_int;
        // lwIP's getaddrinfo only accepts numeric IP literals when
        // AI_NUMERICHOST is set; without it, an arbitrary mcast group
        // like "239.255.0.1" routes through DNS and fails with EAI_FAIL
        // because no resolver is configured. RTPS only ever passes IP
        // literals, so always-numeric is safe.
        hints.ai_flags = AI_NUMERICHOST as c_int;

        let ret = unsafe {
            lwip_getaddrinfo(
                address as *const _,
                port as *const _,
                &hints,
                &mut (*ep)._iptcp,
            )
        };
        dbg_log!("udp_create_endpoint: getaddrinfo ret={}", ret);
        if ret != 0 {
            return -1;
        }

        // lwIP quirk: copy ai_family to sa_family
        unsafe {
            let ai = &*(*ep)._iptcp;
            if !ai.ai_addr.is_null() {
                (*ai.ai_addr).sa_family = ai.ai_family as u8;
            }
        }
        0
    }

    pub fn udp_free_endpoint(ep: *mut c_void) {
        Self::tcp_free_endpoint(ep)
    }

    pub fn udp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let ai = unsafe { &*rep._iptcp };
        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        0
    }

    /// Phase 71.21 — bind a UDP socket for inbound use via lwIP.
    pub fn udp_listen(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        let ai = unsafe { &*rep._iptcp };

        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        let one: c_int = 1;
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_REUSEADDR as c_int,
                &one as *const _ as *const c_void,
                core::mem::size_of::<c_int>() as u32,
            );
        }

        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        if unsafe { lwip_bind(fd, ai.ai_addr, ai.ai_addrlen) } < 0 {
            unsafe { lwip_close(fd) };
            unsafe { (*sock)._socket = -1 };
            return -1;
        }
        0
    }

    pub fn udp_close(sock: *mut c_void) {
        unsafe { lwip_socket_thread_init() };
        let sock = sock as *mut Socket;
        let fd = unsafe { (*sock)._socket };
        if fd >= 0 {
            unsafe {
                lwip_close(fd);
                (*sock)._socket = -1;
            }
        }
    }

    pub fn udp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }
        let mut peer: sockaddr_in = unsafe { core::mem::zeroed() };
        let mut peerlen: u32 = core::mem::size_of::<sockaddr_in>() as u32;
        let n = unsafe {
            lwip_recvfrom(
                sock._socket,
                buf as *mut c_void,
                len,
                0,
                &mut peer as *mut _ as *mut sockaddr,
                &mut peerlen,
            )
        };
        if n > 0 {
            #[cfg(feature = "debug-cortex-m-semihosting")]
            {
                let src = u32::from_be(peer.sin_addr.s_addr);
                dbg_log!(
                    "udp_read: src={}.{}.{}.{}:{} n={}",
                    (src >> 24) & 0xff,
                    (src >> 16) & 0xff,
                    (src >> 8) & 0xff,
                    src & 0xff,
                    u16::from_be(peer.sin_port),
                    n
                );
            }
        }
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        // UDP is datagram-based — read_exact reads one datagram
        Self::udp_read(sock, buf, len)
    }

    pub fn udp_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        if sock._socket < 0 || rep._iptcp.is_null() {
            return usize::MAX;
        }
        let ai = unsafe { &*rep._iptcp };
        let n = unsafe {
            lwip_sendto(
                sock._socket,
                buf as *const c_void,
                len,
                0,
                ai.ai_addr,
                ai.ai_addrlen,
            )
        };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_set_recv_timeout(sock: *const c_void, timeout_ms: u32) {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        // lwIP's `SO_RCVTIMEO` with `{0, 0}` means "no timeout — block
        // forever". Cooperative DDS recv loops (Phase 71.2) call this
        // with `0` to mean non-blocking; honour that via fcntl.
        if timeout_ms == 0 {
            unsafe {
                let flags = lwip_fcntl(sock._socket, F_GETFL as c_int, 0);
                if flags >= 0 {
                    lwip_fcntl(sock._socket, F_SETFL as c_int, flags | O_NONBLOCK as c_int);
                }
            }
            return;
        }
        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                sock._socket,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }
    }
}

// ============================================================================
// Socket helpers
// ============================================================================

impl FreeRtosPlatform {
    pub fn socket_set_non_blocking(sock: *const c_void) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        let flags = unsafe { lwip_fcntl(sock._socket, F_GETFL as c_int, 0) };
        if flags < 0 {
            return -1;
        }
        if unsafe { lwip_fcntl(sock._socket, F_SETFL as c_int, flags | O_NONBLOCK as c_int) } < 0 {
            return -1;
        }
        0
    }

    pub fn socket_accept(sock_in: *const c_void, sock_out: *mut c_void) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let sin = unsafe { &*(sock_in as *const Socket) };
        let sout = sock_out as *mut Socket;
        let mut addr: sockaddr = unsafe { core::mem::zeroed() };
        let mut addrlen: u32 = core::mem::size_of::<sockaddr>() as u32;

        let fd = unsafe { lwip_accept(sin._socket, &mut addr, &mut addrlen) };
        if fd < 0 {
            return -1;
        }

        // Set timeout + options on accepted socket
        let tv = timeval {
            tv_sec: (Z_TRANSPORT_LEASE / 1000) as _,
            tv_usec: 0 as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
            let one: c_int = 1;
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_KEEPALIVE as c_int,
                &one as *const _ as *const c_void,
                4,
            );
            lwip_setsockopt(
                fd,
                IPPROTO_TCP as c_int,
                TCP_NODELAY as c_int,
                &one as *const _ as *const c_void,
                4,
            );
            let ling = linger {
                l_onoff: 1,
                l_linger: (Z_TRANSPORT_LEASE / 1000) as c_int,
            };
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_LINGER as c_int,
                &ling as *const _ as *const c_void,
                core::mem::size_of::<linger>() as u32,
            );
            (*sout)._socket = fd;
        }
        0
    }

    pub fn socket_close(sock: *mut c_void) {
        Self::tcp_close(sock);
    }

    pub fn socket_wait_event(_peers: *mut c_void, _mutex: *mut c_void) -> i8 {
        // Phase 77.22: delegate to the unified `PlatformYield::yield_now()`.
        use nros_platform_api::PlatformYield;
        <Self as PlatformYield>::yield_now();
        0
    }
}

// ============================================================================
// UDP multicast (Phase 97.4 — RTPS SPDP + SEDP discovery)
// ============================================================================
//
// lwIP supports IGMPv1/v2 once `LWIP_IGMP=1` (set in the FreeRTOS
// board crate's `lwipopts.h`). The recv side here:
//   1. Opens a UDP socket on `(0.0.0.0, mc_port)` via the same path
//      `udp_listen` uses (getaddrinfo'd Endpoint).
//   2. Calls `setsockopt(IPPROTO_IP, IP_ADD_MEMBERSHIP, &ip_mreq{...})`
//      to join the multicast group, parsed from `_join` (a null-
//      terminated dotted-quad like `"239.255.0.1\0"`).
// The send side is just `udp_send_to` with the multicast destination
// in the endpoint — lwIP routes it through the default interface as
// long as it's in 224.0.0.0/4.

impl FreeRtosPlatform {
    pub fn mcast_open(
        sock: *mut c_void,
        endpoint: *const c_void,
        lep: *mut c_void,
        timeout_ms: u32,
        _iface: *const u8,
    ) -> i8 {
        // Send-side: a regular UDP socket aimed at the multicast group.
        // No group-join needed for TX (lwIP picks the default interface
        // for 224.0.0.0/4 destinations). Stash the destination endpoint
        // in `lep` for `mcast_send` to consume.
        if !lep.is_null() && !endpoint.is_null() {
            unsafe {
                core::ptr::copy_nonoverlapping(
                    endpoint as *const u8,
                    lep as *mut u8,
                    core::mem::size_of::<Endpoint>(),
                );
            }
        }
        Self::udp_open(sock, endpoint, timeout_ms)
    }

    pub fn mcast_listen(
        sock: *mut c_void,
        endpoint: *const c_void,
        timeout_ms: u32,
        _iface: *const u8,
        join: *const u8,
    ) -> i8 {
        dbg_log!("mcast_listen ENTER");
        // Step 1 — open + bind the recv socket using the existing
        // udp_listen path.
        let rc = Self::udp_listen(sock, endpoint, timeout_ms);
        dbg_log!("mcast_listen: udp_listen rc={}", rc);
        if rc < 0 {
            return rc;
        }

        // Step 2 — parse the join group string (e.g. "239.255.0.1\0")
        // into a u32 (network byte order via inet_addr-like packing).
        let group = if !join.is_null() {
            parse_ipv4_be(join)
        } else {
            0
        };
        dbg_log!("mcast_listen: group=0x{:08x}", group);
        if group == 0 {
            return rc;
        }

        // Step 3 — IP_ADD_MEMBERSHIP via setsockopt.
        let sock_ref = unsafe { &*(sock as *const Socket) };
        let fd = sock_ref._socket;
        dbg_log!("mcast_listen: fd={}", fd);
        if fd < 0 {
            return -1;
        }
        let mreq = ip_mreq {
            imr_multiaddr: in_addr { s_addr: group },
            imr_interface: in_addr {
                s_addr: 0, // INADDR_ANY — let lwIP pick the default iface.
            },
        };
        let setsockopt_rc = unsafe {
            lwip_setsockopt(
                fd,
                IPPROTO_IP as c_int,
                IP_ADD_MEMBERSHIP as c_int,
                &mreq as *const _ as *const c_void,
                core::mem::size_of::<ip_mreq>() as u32,
            )
        };
        dbg_log!("mcast_listen: setsockopt rc={}", setsockopt_rc);
        if setsockopt_rc < 0 {
            unsafe { lwip_close(fd) };
            return -1;
        }

        // `udp_listen` set `SO_RCVTIMEO = {0, 0}` which lwIP treats as
        // "block forever". The cooperative recv loops in
        // `nros-rmw-dds::transport_nros::multicast_recv_loop` need a
        // non-blocking socket so they can yield between reads — so
        // when the caller asked for `timeout_ms = 0` we flip O_NONBLOCK
        // on. Mirrors `udp_set_recv_timeout` for the unicast path.
        if timeout_ms == 0 {
            unsafe {
                let flags = lwip_fcntl(fd, F_GETFL as c_int, 0);
                if flags >= 0 {
                    lwip_fcntl(fd, F_SETFL as c_int, flags | O_NONBLOCK as c_int);
                }
            }
        }
        0
    }

    pub fn mcast_close(
        sockrecv: *mut c_void,
        socksend: *mut c_void,
        _rep: *const c_void,
        _lep: *const c_void,
    ) {
        if !sockrecv.is_null() {
            Self::udp_close(sockrecv);
        }
        if !socksend.is_null() {
            Self::udp_close(socksend);
        }
        // Group is auto-dropped on socket close in lwIP.
    }

    pub fn mcast_read(
        sock: *const c_void,
        buf: *mut u8,
        len: usize,
        _lep: *const c_void,
        _addr: *mut c_void,
    ) -> usize {
        // Same as UDP unicast read — once IP_ADD_MEMBERSHIP is in
        // place, lwIP delivers multicast-destined frames to any UDP
        // socket bound to the matching port.
        Self::udp_read(sock, buf, len)
    }

    pub fn mcast_read_exact(
        sock: *const c_void,
        buf: *mut u8,
        len: usize,
        _lep: *const c_void,
        _addr: *mut c_void,
    ) -> usize {
        Self::udp_read_exact(sock, buf, len)
    }

    pub fn mcast_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        Self::udp_send(sock, buf, len, endpoint)
    }
}

/// Parse a null-terminated dotted-quad ASCII string ("239.255.0.1\0")
/// into a u32 in network byte order (big-endian).
///
/// Returns 0 on parse failure or empty string.
fn parse_ipv4_be(s: *const u8) -> u32 {
    if s.is_null() {
        return 0;
    }
    let mut octets = [0u32; 4];
    let mut idx = 0usize;
    let mut current: u32 = 0;
    let mut has_digit = false;
    let mut p = s;
    loop {
        let ch = unsafe { *p };
        match ch {
            0 => {
                if !has_digit || idx != 3 {
                    return 0;
                }
                octets[3] = current;
                break;
            }
            b'0'..=b'9' => {
                current = current * 10 + (ch - b'0') as u32;
                if current > 255 {
                    return 0;
                }
                has_digit = true;
            }
            b'.' => {
                if !has_digit || idx >= 3 {
                    return 0;
                }
                octets[idx] = current;
                idx += 1;
                current = 0;
                has_digit = false;
            }
            _ => return 0,
        }
        p = unsafe { p.add(1) };
    }
    // Network byte order: octet[0] is the most-significant byte after
    // htonl. lwIP accepts s_addr as the network-byte-order packed
    // value, which on little-endian Cortex-M means the bytes appear
    // reversed relative to the dotted-quad. Pack as [a, b, c, d] from
    // high to low:
    //   s_addr = a | (b << 8) | (c << 16) | (d << 24)
    octets[0] | (octets[1] << 8) | (octets[2] << 16) | (octets[3] << 24)
}

